import React, { useCallback, useEffect, useState } from 'react';
import { Edit2, Loader, Save, Trash2, UserCheck } from 'lucide-react';
import api from '../../services/api';

const initialForm = {
  userId: '',
  allowedPages: 'Pos,Orders,Products,Customers,Reports,Profile,ChangePassword,Overview',
};

const StaffPermissions = () => {
  const [rows, setRows] = useState([]);
  const [users, setUsers] = useState([]);
  const [form, setForm] = useState(initialForm);
  const [editingId, setEditingId] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const [permRes, userRes] = await Promise.all([
        api.get('/staffpermissions'),
        api.get('/users?page=1&pageSize=500'),
      ]);
      setRows(permRes.data || []);
      setUsers(userRes.data?.items || []);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load staff permissions.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const onSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    setError('');
    try {
      const payload = {
        userId: Number(form.userId),
        allowedPages: form.allowedPages,
      };

      if (editingId) {
        await api.put(`/staffpermissions/${editingId}`, payload);
      } else {
        await api.post('/staffpermissions', payload);
      }

      setEditingId(null);
      setForm(initialForm);
      await fetchData();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to save staff permission.');
    } finally {
      setSaving(false);
    }
  };

  const onEdit = (row) => {
    setEditingId(row.id);
    setForm({
      userId: row.userId,
      allowedPages: row.allowedPages || '',
    });
  };

  const onDelete = async (id) => {
    if (!window.confirm('Delete this permission record?')) return;
    try {
      await api.delete(`/staffpermissions/${id}`);
      await fetchData();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to delete permission.');
    }
  };

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-gray-900">Staff Permissions</h2>
      {error && <div className="p-3 text-sm border border-red-200 bg-red-50 text-red-700 rounded-lg">{error}</div>}

      <form onSubmit={onSubmit} className="bg-white border border-gray-200 rounded-xl p-4 grid grid-cols-1 md:grid-cols-3 gap-3">
        <select value={form.userId} onChange={(e) => setForm({ ...form, userId: e.target.value })} className="px-3 py-2 border border-gray-300 rounded-lg" required>
          <option value="">Select user</option>
          {users.map((u) => <option key={u.userId} value={u.userId}>{u.fullName || u.username} ({u.username})</option>)}
        </select>
        <input value={form.allowedPages} onChange={(e) => setForm({ ...form, allowedPages: e.target.value })} className="px-3 py-2 border border-gray-300 rounded-lg" placeholder="Allowed pages (comma separated)" required />
        <div className="flex gap-2">
          <button type="submit" disabled={saving} className="flex-1 inline-flex items-center justify-center gap-2 px-4 py-2 rounded-lg bg-blue-600 text-white"><Save className="w-4 h-4" /> {editingId ? 'Update' : 'Add'}</button>
          {editingId && <button type="button" onClick={() => { setEditingId(null); setForm(initialForm); }} className="px-4 py-2 rounded-lg bg-gray-200">Cancel</button>}
        </div>
      </form>

      <div className="bg-white border border-gray-200 rounded-xl overflow-x-auto">
        {loading ? <div className="py-10 flex justify-center"><Loader className="w-6 h-6 animate-spin text-blue-600" /></div> : (
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase">User</th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Allowed Pages</th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Actions</th>
              </tr>
            </thead>
            <tbody>
              {rows.map((r) => (
                <tr key={r.id} className="border-t border-gray-100">
                  <td className="px-4 py-3 font-medium text-gray-900 inline-flex items-center gap-2"><UserCheck className="w-4 h-4 text-gray-500" /> {r.user?.fullName || r.user?.username || `User #${r.userId}`}</td>
                  <td className="px-4 py-3 text-gray-600">{r.allowedPages}</td>
                  <td className="px-4 py-3">
                    <div className="flex gap-2">
                      <button onClick={() => onEdit(r)} className="p-2 rounded-lg hover:bg-blue-50 text-blue-600"><Edit2 className="w-4 h-4" /></button>
                      <button onClick={() => onDelete(r.id)} className="p-2 rounded-lg hover:bg-red-50 text-red-600"><Trash2 className="w-4 h-4" /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default StaffPermissions;
